    26→fn create_sample_ndjson_file(dir: &TempDir) -> Utf8PathBuf {
    27→    let path = dir.path().join("events.ndjson");
    28→    let event = r#"{"id":1,"timestamp":1710000000000000000,"source":{"adapter":"test","origin":"test"},"transport":"grpc","direction":"outbound","payload":{"type":"raw","raw":"dGVzdA=="},"metadata":{}}"#;
    29→    fs::write(&path, event).unwrap();
    30→    Utf8PathBuf::from_path_buf(path).unwrap()
    31→}
    32→
    33→fn create_sample_proto_file(dir: &TempDir) -> Utf8PathBuf {
    34→    let path = dir.path().join("test.proto");
    35→    let proto_content = r#"
    36→syntax = "proto3";
    37→package test;
    38→
    39→message TestMessage {
    40→    int32 id = 1;
    41→    string name = 2;
    42→}
    43→
    44→service TestService {
    45→    rpc GetTest(TestMessage) returns (TestMessage);
    46→}
    47→"#;
    48→    fs::write(&path, proto_content).unwrap();
    49→    Utf8PathBuf::from_path_buf(path).unwrap()
    50→}
    51→
    52→fn create_sample_otlp_json(dir: &TempDir) -> Utf8PathBuf {
    53→    let path = dir.path().join("traces.json");
    54→    let content = r#"{
    55→        "resourceSpans": [{
    56→            "resource": {
    57→                "attributes": [
    58→                    {"key": "service.name", "value": {"stringValue": "test-service"}}
    59→                ]
    60→            },
    61→            "scopeSpans": [{
    62→                "scope": {"name": "test", "version": "1.0"},
    63→                "spans": [{
    64→                    "traceId": "4bf92f3577b34da6a3ce929d0e0e4736",
    65→                    "spanId": "00f067aa0ba902b7",
    66→                    "name": "/api.v1.Users/Get",
    67→                    "kind": 3,
    68→                    "startTimeUnixNano": "1710000000000000000",
    69→                    "endTimeUnixNano": "1710000000100000000",
    70→                    "attributes": []
    71→                }]
    72→            }]
    73→        }]
    74→    }"#;
    75→    fs::write(&path, content).unwrap();
    76→    Utf8PathBuf::from_path_buf(path).unwrap()
    77→}
    78→
    79→fn create_plugin_dir_with_manifest(dir: &TempDir, plugin_name: &str) -> PathBuf {
    80→    let plugin_dir = dir.path().join(plugin_name);
    81→    fs::create_dir_all(&plugin_dir).unwrap();
    82→
    83→    let manifest = r#"
    84→[plugin]
    85→name = "test-plugin"
    86→version = "1.0.0"
    87→description = "Test plugin"
    88→api_version = "1.0"
    89→protocol_id = "test-proto"
    90→type = "native"
    91→library = "libtest.so"
    92→"#;
    93→    let manifest_path = plugin_dir.join("plugin.toml");
    94→    fs::write(&manifest_path, manifest).unwrap();
    95→
    96→    plugin_dir
    97→}
