    31→            Some("pcap") => Ok(InputFormat::Pcap),
    32→            Some("pcapng") => Ok(InputFormat::Pcapng),
    33→            _ => bail!("Unsupported input format for {}", path.display()),
    34→        };
    35→    }
    36→
    37→    match &magic {
    38→        [0x0a, 0x0d, 0x0d, 0x0a] => Ok(InputFormat::Pcapng),
    39→        [0xa1, 0xb2, 0xc3, 0xd4] | [0xd4, 0xc3, 0xb2, 0xa1] => Ok(InputFormat::Pcap),
    40→        [b'{', ..] | [b'[', ..] => Ok(InputFormat::Json),
    41→        _ => {
    42→            // Fall back to extension
    43→            match path.extension().and_then(|e| e.to_str()) {
    44→                Some("json") => Ok(InputFormat::Json),
    45→                Some("pcap") => Ok(InputFormat::Pcap),
    46→                Some("pcapng") => Ok(InputFormat::Pcapng),
    47→                _ => bail!("Unsupported input format for {}", path.display()),
    48→            }
    49→        }
    50→    }
