     1→//! JSON fixture adapter implementation.
     2→
     3→use crate::error::FixtureError;
     4→use crate::format::{FixtureEvent, FixtureFile};
     5→use bytes::Bytes;
     6→use camino::Utf8PathBuf;
     7→use prb_core::{
     8→    CaptureAdapter, CoreError, DebugEvent, Direction, EventSource, NetworkAddr, Payload,
     9→    Timestamp, TransportKind,
    10→};
    11→use std::fs;
    12→
    13→/// CaptureAdapter that reads JSON fixture files.
    14→pub struct JsonFixtureAdapter {
    15→    path: Utf8PathBuf,
    16→    events: Option<Vec<FixtureEvent>>,
    17→}
    18→
    19→impl JsonFixtureAdapter {
    20→    /// Create a new JSON fixture adapter from a file path.
    21→    pub fn new(path: Utf8PathBuf) -> Self {
    22→        Self {
    23→            path,
    24→            events: None,
    25→        }
    26→    }
    27→
    28→    /// Load and parse the fixture file.
    29→    fn load(&mut self) -> Result<(), FixtureError> {
    30→        if self.events.is_some() {
    31→            return Ok(());
    32→        }
    33→
    34→        let content = fs::read_to_string(&self.path)?;
    35→        let fixture: FixtureFile = serde_json::from_str(&content)?;
    36→
    37→        // Validate version
    38→        if fixture.version != 1 {
    39→            return Err(FixtureError::UnsupportedVersion(fixture.version));
    40→        }
    41→
    42→        self.events = Some(fixture.events);
    43→        Ok(())
    44→    }
    45→
    46→    /// Convert a FixtureEvent to a DebugEvent.
    47→    fn convert_event(&self, event: FixtureEvent) -> Result<DebugEvent, FixtureError> {
    48→        // Parse transport
    49→        let transport = parse_transport(&event.transport)?;
    50→
    51→        // Parse direction
    52→        let direction = parse_direction(&event.direction)?;
    53→
    54→        // Validate and decode payload
    55→        let payload = match (event.payload_base64, event.payload_utf8) {
    56→            (Some(b64), None) => {
    57→                let decoded = base64::Engine::decode(
    58→                    &base64::engine::general_purpose::STANDARD,
    59→                    b64.as_bytes(),
    60→                )
    61→                .map_err(|e| FixtureError::Base64Decode(e.to_string()))?;
    62→                Payload::Raw {
    63→                    raw: Bytes::from(decoded),
    64→                }
    65→            }
    66→            (None, Some(utf8)) => Payload::Raw {
    67→                raw: Bytes::from(utf8.into_bytes()),
    68→            },
    69→            (Some(_), Some(_)) => {
    70→                return Err(FixtureError::invalid_format(
    71→                    "cannot specify both payload_base64 and payload_utf8",
    72→                ))
    73→            }
    74→            (None, None) => {
    75→                return Err(FixtureError::invalid_format(
    76→                    "must specify either payload_base64 or payload_utf8",
    77→                ))
    78→            }
    79→        };
    80→
    81→        // Build event source
    82→        let network = event.source.and_then(|src| {
    83→            if let (Some(src_addr), Some(dst_addr)) = (src.src, src.dst) {
    84→                Some(NetworkAddr {
    85→                    src: src_addr,
    86→                    dst: dst_addr,
    87→                })
    88→            } else {
    89→                None
    90→            }
    91→        });
    92→
    93→        let source = EventSource {
    94→            adapter: "json-fixture".to_string(),
    95→            origin: self.path.to_string(),
    96→            network,
    97→        };
    98→
    99→        // Build the event
   100→        let debug_event = DebugEvent::builder()
   101→            .timestamp(Timestamp::from_nanos(event.timestamp_ns))
   102→            .source(source)
   103→            .transport(transport)
   104→            .direction(direction)
   105→            .payload(payload)
   106→            .build();
   107→
   108→        // Add metadata
   109→        let mut debug_event = debug_event;
   110→        for (key, value) in event.metadata {
   111→            debug_event.metadata.insert(key, value);
   112→        }
   113→
   114→        Ok(debug_event)
   115→    }
   116→
   117→    /// Map FixtureError to CoreError for trait compliance.
   118→    fn map_error(e: FixtureError) -> CoreError {
   119→        match e {
   120→            FixtureError::Base64Decode(msg) => CoreError::PayloadDecode(format!("base64 decode: {}", msg)),
   121→            FixtureError::InvalidTransport(t) => CoreError::UnsupportedTransport(t),
   122→            FixtureError::InvalidFormat(msg) => CoreError::PayloadDecode(format!("invalid format: {}", msg)),
   123→            FixtureError::Parse { source } => CoreError::from(source),
   124→            FixtureError::Io { source } => CoreError::PayloadDecode(format!("I/O error: {}", source)),
   125→            FixtureError::UnsupportedVersion(v) => CoreError::PayloadDecode(format!("unsupported version: {}", v)),
   126→            FixtureError::InvalidDirection(d) => CoreError::PayloadDecode(format!("invalid direction: {}", d)),
   127→            FixtureError::Core(e) => e,
   128→        }
   129→    }
   130→}
   131→
   132→impl CaptureAdapter for JsonFixtureAdapter {
   133→    fn name(&self) -> &str {
   134→        "json-fixture"
   135→    }
   136→
   137→    fn ingest(&mut self) -> Box<dyn Iterator<Item = Result<DebugEvent, CoreError>> + '_> {
   138→        // Attempt to load the file
   139→        if let Err(e) = self.load() {
   140→            return Box::new(std::iter::once(Err(Self::map_error(e))));
   141→        }
   142→
   143→        // Take ownership of events to iterate
   144→        let events = self.events.take().unwrap_or_default();
   145→
   146→        Box::new(events.into_iter().map(|event| {
   147→            self.convert_event(event)
   148→                .map_err(Self::map_error)
   149→        }))
   150→    }
   151→}
   152→
   153→/// Parse a transport string into TransportKind.
   154→fn parse_transport(s: &str) -> Result<TransportKind, FixtureError> {
   155→    match s.to_lowercase().as_str() {
   156→        "grpc" => Ok(TransportKind::Grpc),
   157→        "zmq" => Ok(TransportKind::Zmq),
   158→        "dds-rtps" => Ok(TransportKind::DdsRtps),
   159→        "raw-tcp" | "tcp" => Ok(TransportKind::RawTcp),
   160→        "raw-udp" | "udp" => Ok(TransportKind::RawUdp),
   161→        "json-fixture" => Ok(TransportKind::JsonFixture),
   162→        _ => Err(FixtureError::InvalidTransport(s.to_string())),
   163→    }
